import{_ as o,C as a,o as r,c as n,E as i,a2 as l}from"./chunks/framework.CkaEw-3u.js";const y=JSON.parse('{"title":"モーフアニメーションを作る","description":"文字列から別の文字列へ滑らかに変形させる手順と調整のコツ","frontmatter":{"title":"モーフアニメーションを作る","description":"文字列から別の文字列へ滑らかに変形させる手順と調整のコツ","pageClass":"feature-guide","aside":false,"head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/features/feature-morph.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"ja_JP"}],["meta",{"property":"og:title","content":"モーフアニメーションを作る | Mug Typography Manual"}],["meta",{"property":"og:description","content":"文字列から別の文字列へ滑らかに変形させる手順と調整のコツ"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/features/feature-morph.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.png"}],["meta",{"property":"og:image:type","content":"image/png"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"モーフアニメーションを作る | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"文字列から別の文字列へ滑らかに変形させる手順と調整のコツ"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.png"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"features/feature-morph.md","filePath":"features/feature-morph.md"}'),s={name:"features/feature-morph.md"};function g(c,t,p,d,m,h){const e=a("FeatureHero");return r(),n("div",null,[i(e,{eyebrow:"MORPH & TRANSITION",title:"流れるように言葉が言葉に変わる",description:"元のテキストから別のテキストへ、文字のかたちを自動で対応づけて滑らかに変形。Progressへキーフレームを2つ置くだけで、文字が溶け合うトランジションを作れます。",image:"/image/morph.webp","image-alt":"文字列が別の文字列へ変形するモーフアニメーション","detail-link":"/reference/reference-global-settings#-モーフアニメーション-morph-animation","point-one":"キーフレーム2つで完成","point-two":"自然な変形アルゴリズム","point-three":"字数違いに対応"}),t[0]||(t[0]=l('<h2 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h2><ol><li><strong>Page</strong> を <code>Global Settings</code> にします。</li><li><strong>Text</strong> に変形元の文字列を入力します。</li><li><strong>Morph Animation</strong> 内の <strong>Enable Morph</strong> をオンにします。</li><li><strong>To Text</strong> に変形先の文字列を入力します。</li><li>開始フレームで <strong>Progress</strong> を <code>0</code> にしてキーフレームを設定します。</li><li>終了フレームで Progress を <code>1</code> にします。</li></ol><p><code>0</code> は Text、<code>1</code> は To Text の形です。中間の値では両者のパーツを補間します。キーフレームの間隔とカーブで速度感を調整してください。</p><h2 id="連続して変形させる" tabindex="-1">連続して変形させる <a class="header-anchor" href="#連続して変形させる" aria-label="Permalink to &quot;連続して変形させる&quot;">​</a></h2><p>A→B→C のように、3つ以上の文字列を続けて変形させることもできます。</p><ol><li>最初のモーフが完了したフレームで、<strong>Text</strong> を To Text と同じ文字列に変更してキーフレームを設定し、<strong>Progress</strong> を <code>0</code> に戻します。</li><li>同じフレームで <strong>To Text</strong> も次の文字列に変更してキーフレームを設定し、再び Progress を <code>1</code> へアニメーションさせます。</li></ol><p>Progress が <code>1</code> のときの表示と、Text を差し替えて <code>0</code> に戻した直後の表示は同じ形になるため、切り替えは画面上では目立ちません。これを繰り返すことで、いくつでも変化を連鎖できます。</p><h2 id="対応づけを調整する" tabindex="-1">対応づけを調整する <a class="header-anchor" href="#対応づけを調整する" aria-label="Permalink to &quot;対応づけを調整する&quot;">​</a></h2><p>文字数や形が大きく異なるときは、内部で「どのパーツからどのパーツへ変形するか」を推定します。</p><table tabindex="0"><thead><tr><th>パラメーター</th><th>調整する場面</th></tr></thead><tbody><tr><td><strong>Matching Strength</strong></td><td>面積の近さを重視して対応づけたいとき。<code>0</code> では位置の近さを優先します。</td></tr><tr><td><strong>Same Glyph Priority</strong></td><td>両方に同じ文字があるとき、その文字同士を優先して結びたいとき。</td></tr></tbody></table><h2 id="きれいに見せるコツ" tabindex="-1">きれいに見せるコツ <a class="header-anchor" href="#きれいに見せるコツ" aria-label="Permalink to &quot;きれいに見せるコツ&quot;">​</a></h2><ul><li>まずデフォルト値で動きを確認し、パーツが不自然に交差するときだけ <strong>Matching Strength</strong> などを少しずつ変更します。</li><li>同じ文字を同じ位置に残したい場合は Same Glyph Priority を上げます。</li><li>形が大きく異なる文字列では、Progress の中間を短くすると変形の複雑さが目立ちにくくなります。</li><li>縦方向の位置が揺れる場合は Vertical Alignment の <code>Baseline</code> を試します。</li><li>対応づけが思い通りにならないときは、<strong>Horizontal Alignment</strong> を <code>Center</code> から <code>Left</code> や <code>Right</code> に変更してみます。文字の位置関係が変わるため、対応づけの結果も変化します。</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>パーツの分かれ方はフォントのアウトライン構造に依存します。同じ文字列でも、フォントを変えるとモーフの対応や動きが変わることがあります。</p></div>',13))])}const b=o(s,[["render",g]]);export{y as __pageData,b as default};
